    storyConsequence: { correct: { zh: '两段行军——坐标精准！做得漂亮！', en: 'Two-Stage March — Well done!' }, wrong: { zh: '位置差了一点——试试重新读一下坐标？', en: 'Not quite... Try again!' } }
