    tutorialSteps: [
      { text: { zh: '诸葛亮：为什么用正弦算面积？\n底×高÷2 需要知道高——但实际中"高"很难量！\n知道两边和夹角就够了：$\\frac{1}{2}ab\\sin C$ 直接给出面积。', en: 'Zhuge Liang: "Why use sine for area?\nBase × height ÷ 2 needs the height — but height is hard to measure!\nKnowing two sides and included angle is enough: $\\frac{1}{2}ab\\sin C$ gives area directly."' }, highlightField: 'ans' },
      { text: { zh: '诸葛亮：正弦面积公式\n$$A = \\frac{1}{2}ab\\sin C$$\n$a$、$b$ = 两条边，$C$ = 它们的夹角。', en: 'Zhuge Liang: "Sine area formula\n$$A = \\frac{1}{2}ab\\sin C$$\n$a$, $b$ = two sides, $C$ = included angle."' }, highlightField: 'ans' },
      { text: { zh: '诸葛亮：代入\n$A = \\frac{1}{2} \\times 6 \\times 8 \\times \\sin 30°$\n$\\sin 30° = 0.5$', en: 'Zhuge Liang: "Substitute\n$A = \\frac{1}{2} \\times 6 \\times 8 \\times \\sin 30°$\n$\\sin 30° = 0.5$"' }, highlightField: 'ans' },
      { text: { zh: '诸葛亮：计算\n$A = \\frac{1}{2} \\times 6 \\times 8 \\times 0.5 = \\frac{1}{2} \\times 24 = 12$', en: 'Zhuge Liang: "Calculate\n$A = \\frac{1}{2} \\times 6 \\times 8 \\times 0.5 = \\frac{1}{2} \\times 24 = 12$"' }, highlightField: 'ans' },
      { text: { zh: '诸葛亮：答案\n面积 = $12$ 平方单位', en: 'Zhuge Liang: "Answer\nArea = $12$ square units"' }, highlightField: 'ans' },
      { text: { zh: '诸葛亮：验算\n用底×高：底=8，高=6×sin30°=3\n面积=½×8×3=12 ✓ 两种方法一致！', en: 'Zhuge Liang: "Verify\nUsing base × height: base=8, height=6×sin30°=3\nArea=½×8×3=12 ✓ Both methods agree!"' }, highlightField: 'ans' },
    ],
    secret: { concept: { zh: '三角形面积=½absinC。不需要高，只需两边和夹角。', en: 'Triangle area = ½absinC. No height needed, just two sides and included angle.' }, formula: '$A = \\frac{1}{2}ab\\sin C$', tips: [{ zh: '诸葛亮提示：两边夹角→正弦面积公式！', en: 'Zhuge Liang Tip: Two sides + included angle → sine area formula!' }] },
    storyConsequence: { correct: { zh: '三角面积——12平方单位精准！', en: 'Trig Area — 12 square units precise!' }, wrong: { zh: '½×6×8×sin30°=½×6×8×0.5=12。', en: '½×6×8×sin30°=½×6×8×0.5=12.' } },
